import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Initialize aliyun command with separate arguments to eliminate shell injection risk
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Initialize jq command with fixed filter as direct argument
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create pipe to connect aliyun's stdout to jq's stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create output pipe for aliyun command: %w", err)
	}
	defer aliyunStdout.Close()
	jqCmd.Stdin = aliyunStdout

	// Capture stderr from both commands for detailed error diagnosis
	var aliyunStderr, jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Capture jq's processed output (the pipeline result)
	var jqOutput bytes.Buffer
	jqCmd.Stdout = &jqOutput

	// Start aliyun command execution in the background
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to launch aliyun command: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Execute jq command and wait for it to complete
	if err := jqCmd.Run(); err != nil {
		// Collect aliyun execution status if jq fails
		aliyunErr := aliyunCmd.Wait()
		if aliyunErr != nil {
			return "", fmt.Errorf("jq processing failed: %w, jq stderr: %s; aliyun error: %w, aliyun stderr: %s", err, jqStderr.String(), aliyunErr, aliyunStderr.String())
		}
		return "", fmt.Errorf("jq processing failed: %w, jq stderr: %s", err, jqStderr.String())
	}

	// Wait for aliyun to finish and check for execution errors
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	result := jqOutput.String()

	// Write the processed result to the specified output file
	if err := os.WriteFile(outputFile, []byte(result), 0644); err != nil {
		// Return the successful command result even if file write fails
		return result, fmt.Errorf("failed to save output to file %q: %w", outputFile, err)
	}

	return result, nil
}

