package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Construct aliyun SLB query command
	aliyunCmd := exec.Command("aliyun",
		"slb",
		"DescribeLoadBalancers",
		"--LoadBalancerName",
		loadBalancerName,
	)

	// Capture stderr from aliyun command for error reporting
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr

	// Create pipe to forward aliyun stdout to jq stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err!= nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}

	// Construct jq command to format output
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Capture stderr from jq command for error reporting
	var jqStderr bytes.Buffer
	jqCmd.Stderr = &jqStderr

	// Connect aliyun's output to jq's input
	jqCmd.Stdin = aliyunStdout

	// Create and open output file (matches shell '>' behavior: create/truncate)
	outFile, err := os.Create(outputFile)
	if err!= nil {
		return "", fmt.Errorf("failed to create output file %q: %w", outputFile, err)
	}
	defer outFile.Close()

	// Redirect jq's stdout directly to the output file
	jqCmd.Stdout = outFile

	// Start aliyun command execution
	if err := aliyunCmd.Start(); err!= nil {
		return "", fmt.Errorf("failed to start aliyun command: %w\naliyun stderr: %s",
			err, aliyunStderr.String())
	}

	// Start jq command execution
	if err := jqCmd.Start(); err!= nil {
		// Clean up aliyun process if jq fails to start
		_ = aliyunCmd.Process.Kill()
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w\njq stderr: %s",
			err, jqStderr.String())
	}

	// Wait for jq to finish first (avoids pipe deadlock as jq is the reader)
	if err := jqCmd.Wait(); err!= nil {
		// Clean up aliyun process
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("jq execution failed: %w\njq stderr: %s\naliyun stderr: %s",
			err, jqStderr.String(), aliyunStderr.String())
	}

	// Wait for aliyun command to complete and check for errors
	if err := aliyunCmd.Wait(); err!= nil {
		return "", fmt.Errorf("aliyun execution failed: %w\naliyun stderr: %s",
			err, aliyunStderr.String())
	}

	successMsg := fmt.Sprintf("Successfully exported SLB data for %q to %q",
		loadBalancerName, outputFile)
	return successMsg, nil
}

func main() {
	if len(os.Args)!= 3 {
		fmt.Printf("Usage: %s <load-balancer-name> <output-file-path>\n", os.Args[0])
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err!= nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(result)
}

