// QuerySLBAndExport executes the aliyun SLB query pipeline, filters results with jq, and saves to output file
// Returns combined diagnostic output (stderr) and execution status, plus any error encountered
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Initialize aliyun CLI command to fetch SLB information
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	// Initialize jq command to format the JSON output as required
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Buffer to capture stderr from both commands for debugging and result reporting
	var stderrBuf bytes.Buffer
	aliyunCmd.Stderr = &stderrBuf
	jqCmd.Stderr = &stderrBuf

	// Create pipe to forward stdout of aliyun command to stdin of jq command
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err!= nil {
		return stderrBuf.String(), fmt.Errorf("failed to create output pipe for aliyun command: %w", err)
	}
	defer aliyunStdout.Close() // Ensure pipe is cleaned up on exit
	jqCmd.Stdin = aliyunStdout

	// Create output file (truncates if it already exists, matches bash > behavior)
	outFile, err := os.Create(outputFile)
	if err!= nil {
		return stderrBuf.String(), fmt.Errorf("failed to create output file %q: %w", outputFile, err)
	}
	defer outFile.Close() // Ensure file descriptor is closed on exit
	jqCmd.Stdout = outFile

	// Start the aliyun command execution (non-blocking)
	if err := aliyunCmd.Start(); err!= nil {
		return stderrBuf.String(), fmt.Errorf("failed to launch aliyun command: %w", err)
	}

	// Run jq command and block until it completes
	if err := jqCmd.Run(); err!= nil {
		// Clean up aliyun process if jq fails early to avoid zombie processes
		aliyunErr := aliyunCmd.Wait()
		if aliyunErr!= nil {
			return stderrBuf.String(), fmt.Errorf("aliyun execution failed: %w; jq execution failed: %w", aliyunErr, err)
		}
		return stderrBuf.String(), fmt.Errorf("jq execution failed: %w", err)
	}

	// Wait for aliyun command to complete and check for execution errors
	if err := aliyunCmd.Wait(); err!= nil {
		return stderrBuf.String(), fmt.Errorf("aliyun execution failed: %w", err)
	}

	// Construct success result including any warning output from stderr
	result := stderrBuf.String()
	if result!= "" {
		result += "\n"
	}
	result += fmt.Sprintf("Successfully exported SLB information to %q", outputFile)

	return result, nil
}

// main provides a command-line interface for the QuerySLBAndExport function
