// QuerySLBAndExport executes the aliyun SLB query command pipeline and exports results to a file
// loadBalancerName: the name of the SLB instance to query
// outputFile: path to save the formatted JSON result
// Returns: combined stderr output from commands, and any execution error
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create output file (truncates if exists, equivalent to shell > redirect)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Initialize aliyun CLI command with specified load balancer name
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	// Initialize jq command with the required JSON filter
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Capture stderr from both commands to return as execution result
	var stderrBuf bytes.Buffer
	aliyunCmd.Stderr = &stderrBuf
	jqCmd.Stderr = &stderrBuf

	// Pipe stdout of aliyun command to stdin of jq command
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return stderrBuf.String(), fmt.Errorf("failed to create command pipeline: %w", err)
	}

	// Redirect jq's stdout to the output file
	jqCmd.Stdout = outFile

	// Start downstream jq command first (required for pipeline execution)
	if err := jqCmd.Start(); err != nil {
		return stderrBuf.String(), fmt.Errorf("failed to start jq process: %w", err)
	}

	// Run upstream aliyun command (blocks until execution completes)
	aliyunErr := aliyunCmd.Run()
	// Wait for jq to finish processing all input, regardless of aliyun's result
	jqErr := jqCmd.Wait()

	// Combine errors from both commands if any
	var combinedErr error
	if aliyunErr != nil {
		combinedErr = errors.Join(combinedErr, fmt.Errorf("aliyun command failed: %w", aliyunErr))
	}
	if jqErr != nil {
		combinedErr = errors.Join(combinedErr, fmt.Errorf("jq command failed: %w", jqErr))
	}

	return stderrBuf.String(), combinedErr
}

func main() {
	// Basic command line argument validation
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <load-balancer-name> <output-file-path>\n", os.Args[0])
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputPath := os.Args[2]

	// Execute the SLB query and export function
	output, err := QuerySLBAndExport(loadBalancerName, outputPath)

	// Print any command output (stderr)
	if output != "" {
