		fmt.Println(output)
	}

	// Handle execution errors
	if err != nil {
		fmt.Printf("Execution failed: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Success! SLB information has been exported to %s\n", outputPath)
}

