	const cmdStr = `aliyun slb DescribeLoadBalancers --LoadBalancerName "$LOAD_BALANCER_NAME" | jq '.LoadBalancers.LoadBalancer[]' > "$OUTPUT_FILE"`

	cmd := exec.Command("sh", "-c", cmdStr)

	// Pass user-controlled parameters as environment variables (safely expanded by the shell)
	cmd.Env = append(os.Environ(),
		fmt.Sprintf("LOAD_BALANCER_NAME=%s", loadBalancerName),
		fmt.Sprintf("OUTPUT_FILE=%s", outputFile),
	)

	// Capture combined stdout and stderr (stdout is empty due to redirection to output file)
	outputBytes, err := cmd.CombinedOutput()
	outputStr := string(outputBytes)

	if err!= nil {
		return outputStr, fmt.Errorf("command failed: %w, output: %s", err, outputStr)
	}

	return outputStr, nil
}

