// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stderr output of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create output file to write jq processed results
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Buffer to collect stderr from both commands (matches original combined output behavior)
	var stderrBuf bytes.Buffer

	// Build aliyun command: use --flag=value syntax to prevent argument injection
	// User input is directly passed as a single argument part, no shell parsing
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName="+loadBalancerName)
	aliyunCmd.Stderr = &stderrBuf

	// Create pipe to connect aliyun's stdout directly to jq's stdin (streaming pipeline)
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return stderrBuf.String(), fmt.Errorf("command failed: %w, output: %s", err, stderrBuf.String())
	}

	// Build jq command with fixed filter (no user-controlled input here)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout
	jqCmd.Stdout = outFile // Directly write jq output to file, no shell redirection
	jqCmd.Stderr = &stderrBuf

	// Start aliyun command first
	if err := aliyunCmd.Start(); err != nil {
		return stderrBuf.String(), fmt.Errorf("command failed: %w, output: %s", err, stderrBuf.String())
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		// Clean up aliyun process if jq fails to start
		aliyunCmd.Process.Kill()
		aliyunCmd.Wait()
		return stderrBuf.String(), fmt.Errorf("command failed: %w, output: %s", err, stderrBuf.String())
	}

	// Wait for aliyun to complete execution
	if err := aliyunCmd.Wait(); err != nil {
		// Ensure jq exits cleanly even if aliyun fails
		jqCmd.Wait()
		return stderrBuf.String(), fmt.Errorf("command failed: %w, output: %s", err, stderrBuf.String())
	}

	// Wait for jq to complete processing
	if err := jqCmd.Wait(); err != nil {
		return stderrBuf.String(), fmt.Errorf("command failed: %w, output: %s", err, stderrBuf.String())
	}

	// Return any captured stderr (may be empty if no warnings/errors)
	return stderrBuf.String(), nil
}

