import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create aliyun command with direct arguments to eliminate shell injection risk
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr // Capture aliyun error output for debugging

	// Create jq command with filter as direct argument
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	var jqStderr bytes.Buffer
	jqCmd.Stderr = &jqStderr // Capture jq error output for debugging

	// Connect aliyun's stdout to jq's stdin via pipe (native pipeline, no shell involved)
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err!= nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}
	jqCmd.Stdin = aliyunStdout

	// Start aliyun command execution
	if err := aliyunCmd.Start(); err!= nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, aliyun stderr: %s", err, aliyunStderr.String())
	}

	// Run jq command and capture its stdout (the processed pipeline output)
	jqOutput, jqErr := jqCmd.Output()

	// Wait for aliyun to complete and check for execution errors
	aliyunErr := aliyunCmd.Wait()

	// Aggregate errors from both commands in the pipeline
	if aliyunErr!= nil || jqErr!= nil {
		var errDetails strings.Builder
		errDetails.WriteString("pipeline execution failed: ")
		if aliyunErr!= nil {
			errDetails.WriteString(fmt.Sprintf("aliyun error: %v; ", aliyunErr))
			if aliyunStderr.Len() > 0 {
				errDetails.WriteString(fmt.Sprintf("aliyun stderr: %q; ", aliyunStderr.String()))
			}
		}
		if jqErr!= nil {
			errDetails.WriteString(fmt.Sprintf("jq error: %v; ", jqErr))
			if jqStderr.Len() > 0 {
				errDetails.WriteString(fmt.Sprintf("jq stderr: %q; ", jqStderr.String()))
			}
		}
		return string(jqOutput), fmt.Errorf("%s", errDetails.String())
	}

	// Write processed jq output to the specified output file
	if err := os.WriteFile(outputFile, jqOutput, 0o644); err!= nil {
		return string(jqOutput), fmt.Errorf("failed to write output to %q: %w", outputFile, err)
	}

	// Return the actual pipeline stdout (jq processed data) as the result
	return string(jqOutput), nil
}

