package main
import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)
// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation for required parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}
	// Initialize aliyun command with explicit arguments to eliminate shell injection risk
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	// Initialize jq command with fixed filter expression (no user-controlled input here)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	// Capture stderr from both commands for detailed error reporting
	var stderrBuf bytes.Buffer
	aliyunCmd.Stderr = &stderrBuf
	jqCmd.Stderr = &stderrBuf
	// Create pipeline: connect aliyun's stdout directly to jq's stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err!= nil {
		return "", fmt.Errorf("failed to create pipeline between aliyun and jq: %w, stderr: %s", err, stderrBuf.String())
	}
	jqCmd.Stdin = aliyunStdout
	// Capture jq's processed output (this is the pipeline result)
	var jqStdoutBuf bytes.Buffer
	jqCmd.Stdout = &jqStdoutBuf
	// Start aliyun command execution
	if err := aliyunCmd.Start(); err!= nil {
		return "", fmt.Errorf("failed to launch aliyun command: %w, stderr: %s", err, stderrBuf.String())
	}
	// Start jq command execution
	if err := jqCmd.Start(); err!= nil {
		// Clean up aliyun process if jq fails to start
		_ = aliyunCmd.Process.Kill()
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("failed to launch jq command: %w, stderr: %s", err, stderrBuf.String())
	}
	// Wait for aliyun to finish generating output
	if err := aliyunCmd.Wait(); err!= nil {
		// Ensure jq exits properly after aliyun's stdout is closed
		_ = jqCmd.Wait()
		return jqStdoutBuf.String(), fmt.Errorf("aliyun command execution failed: %w, stderr: %s", err, stderrBuf.String())
	}
	// Wait for jq to finish processing all input
	if err := jqCmd.Wait(); err!= nil {
		return jqStdoutBuf.String(), fmt.Errorf("jq processing failed: %w, stderr: %s", err, stderrBuf.String())
	}
	// Write the processed JSON output to the specified file
	outputContent := jqStdoutBuf.Bytes()
	if err := os.WriteFile(outputFile, outputContent, 0644); err!= nil {
		return string(outputContent), fmt.Errorf("failed to write output to file %q: %w", outputFile, err)
	}
	// Return the processed pipeline output as the function result
	return string(outputContent), nil
}

