package main
import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)
// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the combined stderr output of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Initialize commands with direct, separate arguments to completely eliminate shell injection risk
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	// Capture combined stderr from both commands to match original behavior
	var combinedStderr bytes.Buffer
	aliyunCmd.Stderr = &combinedStderr
	jqCmd.Stderr = &combinedStderr
	// Create pipe to connect aliyun's stdout to jq's stdin (no shell involvement)
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err!= nil {
		return combinedStderr.String(), fmt.Errorf("failed to create output pipe for aliyun command: %w", err)
	}
	jqCmd.Stdin = aliyunStdout
	// Open output file directly via OS API (avoids shell redirection parsing vulnerabilities)
	outFile, err := os.Create(outputFile)
	if err!= nil {
		return combinedStderr.String(), fmt.Errorf("failed to create output file %q: %w", outputFile, err)
	}
	defer outFile.Close()
	jqCmd.Stdout = outFile
	// Start jq first to ensure it's ready to consume aliyun's output
	if err := jqCmd.Start(); err!= nil {
		return combinedStderr.String(), fmt.Errorf("failed to start jq process: %w", err)
	}
	// Run aliyun command (blocks until execution completes)
	if err := aliyunCmd.Run(); err!= nil {
		// Wait for jq to exit to avoid zombie processes
		jqWaitErr := jqCmd.Wait()
		if jqWaitErr!= nil {
			return combinedStderr.String(), fmt.Errorf("aliyun command failed: %w; jq also failed: %w", err, jqWaitErr)
		}
		return combinedStderr.String(), fmt.Errorf("aliyun command failed: %w", err)
	}
	// Wait for jq to finish processing all input and exit
	if err := jqCmd.Wait(); err!= nil {
		return combinedStderr.String(), fmt.Errorf("jq processing failed: %w", err)
	}
	// Return any captured stderr (empty on successful execution)
	return combinedStderr.String(), nil
}

