// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic validation for required parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}
	// Initialize aliyun SLB query command (no shell injection risk as arguments are passed directly)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	// Create pipe to connect aliyun's stdout to jq's stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err!= nil {
		return "", fmt.Errorf("failed to create output pipe for aliyun command: %w", err)
	}
	// Initialize jq command with fixed filter (no quotes needed as we bypass shell parsing)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout
	var jqStderr bytes.Buffer
	jqCmd.Stderr = &jqStderr
	// Create output file (matches shell > truncate behavior)
	outFile, err := os.Create(outputFile)
	if err!= nil {
		return "", fmt.Errorf("failed to create output file %q: %w", outputFile, err)
	}
	defer outFile.Close()
	// Multi-writer to capture jq output both for return value and file write
	var outputBuf bytes.Buffer
	jqCmd.Stdout = io.MultiWriter(&outputBuf, outFile)
	// Start aliyun command execution
	if err := aliyunCmd.Start(); err!= nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, aliyunStderr.String())
	}
	// Start jq command execution
	if err := jqCmd.Start(); err!= nil {
		// Clean up aliyun process to avoid hanging when jq fails to start
		if killErr := aliyunCmd.Process.Kill(); killErr!= nil {
			return "", fmt.Errorf("failed to start jq: %w, additionally failed to terminate aliyun process: %v, aliyun stderr: %s", err, killErr, aliyunStderr.String())
		}
		aliyunCmd.Wait() // Release process resources
		return "", fmt.Errorf("failed to start jq command: %w, stderr: %s", err, jqStderr.String())
	}
	// Wait for both commands to complete execution
	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()
	// Check for aliyun execution failures (fixes original pipe exit code issue)
	if aliyunErr!= nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, aliyunStderr.String())
	}
	// Check for jq execution failures
	if jqErr!= nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, jqStderr.String())
	}
	// Return the processed output that was written to the file (matches function comment)
	return outputBuf.String(), nil
}

